import 'package:flutter/material.dart';import 'screens/screens.dart';
void main()async{WidgetsFlutterBinding.ensureInitialized();runApp(const FreshLaneApp());}
class FreshLaneApp extends StatelessWidget{const FreshLaneApp({super.key});@override Widget build(BuildContext context)=>MaterialApp(debugShowCheckedModeBanner:false,title:'FreshLane',theme:ThemeData(colorScheme:ColorScheme.fromSeed(seedColor:const Color(0xff15945a)),useMaterial3:true),routes:{'/':(_)=>const Splash(),'/home':(_)=>const HomeScreen(),'/login':(_)=>const PlaceholderScreen('Phone OTP login'),'/profile':(_)=>const PlaceholderScreen('Profile & addresses')});}
class Splash extends StatefulWidget{const Splash({super.key});@override State<Splash> createState()=>_SplashState();}class _SplashState extends State<Splash>{@override void initState(){super.initState();Future.delayed(const Duration(milliseconds:900),()=>mounted?Navigator.pushReplacementNamed(context,'/home'):null);}@override Widget build(BuildContext context)=>const Scaffold(body:Center(child:Text('FreshLane',style:TextStyle(fontSize:36,fontWeight:FontWeight.bold,color:Color(0xff15945a)))));}
